#### 2. **Core Bluetooth Framework (iOS)**
For iOS, the Core Bluetooth framework can be used to interact with Bluetooth beacons. This framework provides a way to discover and communicate with BLE devices.

```swift
import CoreBluetooth

class BeaconManager: NSObject, CBCentralManagerDelegate, CBPeripheralDelegate {

    let centralManager = CBCentralManager(delegate: self, queue: nil)
    var discoveredPeripherals: [CBPeripheral] = []

    override init() {
        super.init()
        centralManager.delegate = self
        centralManager.scanForPeripherals(withServices: nil, options: nil)
    }

    func centralManagerDidUpdateState(_ central: CBCentralManager) {
        if central.state == .poweredOn {
            centralManager.scanForPeripherals(withServices: nil, options: nil)
        } else {
            print("Bluetooth is not available.")
        }
    }

    func centralManager(_ central: CBCentralManager, didDiscover peripheral: CBPeripheral, advertisementData: [String : Any], rssi RSSI: NSNumber) {
        discoveredPeripherals.append(peripheral)
        print("Discovered beacon: \(peripheral.name ?? "Unknown")")
    }
}
```

